1. 見積書PDF (先ほどダウンロードしたもの)
2. 現地案内図
3. 平面図
---
`;

    const mailtoUrl = `mailto:takishita@kashiwa-f.com?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
    window.location.href = mailtoUrl;
    setIsMailModalOpen(false);
